SELECT DATE(created_at) AS access_date, COUNT(DISTINCT user_id) AS unique_users
FROM access_logs
GROUP BY access_date;

SELECT al.access_type, u.user_name
FROM access_logs al
JOIN users u ON al.user_id = u.user_id;

SELECT DISTINCT al.user_id
FROM access_logs al
INNER JOIN market_data md ON al.size_id = md.size_id;

SELECT sizes.size_name, market_data.demand_percentage, market_data.customer_satisfaction
FROM sizes
JOIN market_data ON sizes.size_id = market_data.size_id;
